    43→        // console.log(uploadedImagePaths);
    44→        const message = await deleteJournalImage(session?.access_token, uploadedImagePaths)
    45→        if(message){
    46→          console.log(message.message)
    47→        }
    48→
    49→      }
    50→        editor.update(() => {
    51→            const state = editor.getEditorState().toJSON();
    52→            console.log(state)
    53→            
    54→            const root = $getRoot();
    55→            root.clear();
    56→            onClose();
    57→        })
    58→    }, [editor, onClose, uploadedImagePaths])
    59→
    60→    const handleCloseEditorOnSave = useCallback(async() => {
    61→      editor.update(() => {
    62→            const state = editor.getEditorState().toJSON();
    63→            console.log(state)
    64→            
    65→            const root = $getRoot();
    66→            root.clear();
    67→            onClose();
    68→      })
    69→    }, [onClose, editor])
    70→
    71→    return(
    72→        <>
    73→        <div className='editor-parent-container'>
    74→
    75→            <motion.div 
    76→            initial={{scale: 0, opacity: 0.8}}
