    43→    // const [textContent, setTextContent] = useState('')
    44→    const [hasContent, setHasContent] = useState(false);
    45→    const [isSending, setIsSending] = useState(false);
    46→
    47→    const {session, user} = useAuth();
    48→
    49→    const queryClient = useQueryClient();
    50→
    51→    const handleClickSave = async(e, title) =>{
    52→        e.stopPropagation();
    53→        setIsSending(true)
    54→        try {
    55→             // console.log(editorState);
    56→            const formdata = new FormData();
    57→            if(title && editorState){
    58→                formdata.append('title', title)
    59→                formdata.append('content', editorState)
    60→            }
    61→            const saveData = await saveJournal(session?.access_token, formdata)
    62→
    63→            if(saveData){
    64→                console.log(saveData)
    65→                queryClient.invalidateQueries({queryKey: ['journals']});
    66→                queryClient.invalidateQueries({queryKey: ['userJournals', user?.userData?.[0].id]})
