    21→const ToolBar = () =>{
    22→    //bold and italic style are textFormatTypeStrings
    23→    const [editor] = useLexicalComposerContext();
    24→    const {session} = useAuth();
    25→
    26→
    27→    const applyTextFormat = (format) => {
    28→        editor.dispatchCommand(FORMAT_TEXT_COMMAND, format)
    29→    }
    30→
    31→    //heading node (H1, H2, H3)
    32→    const setHeading = (tag) => {
    33→        editor.update(() => {
    34→            const selection = $getSelection();
    35→            if ($isRangeSelection(selection)) {
    36→                const anchorNode = selection.anchor.getNode();
    37→                
    38→                let element;
    39→                try {
    40→                    element = anchorNode.getKey() === 'root' //checking if anchorNode itselt is the root
    41→                        ? anchorNode  //if not then use getTopLevelElement() method first then as a fallback use getTopLevelElementOrThrow() method
    42→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
    43→                } catch (e) {
    44→                    console.error('Could not get top level element:', e);
    45→                    return;
    46→                }
    47→
    48→                if (!element) return;
    49→
    50→                const type = typeof element.getType === 'function' ? element.getType() : null; //check if elements have getType() === function sometimes nodes dont have getType
    51→                // console.log('Element type:', type);
    52→
    53→                if (type && type !== "paragraph" && type !== "heading") { //only proceed if element is paragraph or heading
    54→                    return;
    55→                }
    56→
    57→                const isActive = $isHeadingNode(element) && element.getTag() === tag; //checking if element.getTag() === 'tag. returns a boolean
    58→
    59→                //use $setBlocksType to change the block type
    60→                //return paragraph if already active(toggle back) otherwise create heading
    61→                $setBlocksType(selection, () => 
    62→                    isActive ? $createParagraphNode() : $createHeadingNode(tag)
    63→                );
    64→            }
    65→        })
    66→    }
    67→
    68→    //align element (left, center, right) using FORMAT_ELEMENT_COMMAND values 'left'|'center'|'right
    69→    const setAlignment = (value) => {
    70→        editor.dispatchCommand(FORMAT_ELEMENT_COMMAND, value);
    71→    }
    72→
    73→    //insert image
    74→    const insertImageFromFile = async() => {
    75→        
    76→        const handleOnChange = async(e) => {
    77→            const filedata = e.target.files?.[0];
    78→            if(!filedata) return;
    79→
    80→            const formdata = new FormData();
    81→            formdata.append('image', filedata);
    82→
    83→            const data_url = await saveJournalImage(session?.access_token, formdata);
    84→            if(!data_url){
    85→                return console.log('error: no image_url')
    86→            }
    87→
    88→            editor.dispatchCommand(INSERT_IMAGE_COMMAND, {
    89→                src: data_url.img_url,
    90→                width: 500,
    91→                height: 500,
    92→            })
    93→        }
    94→
    95→        const input = document.createElement('input'); //create an input element
    96→        input.type = 'file'
    97→        input.accept = 'image/*';
    98→        input.onchange = (e) => {handleOnChange(e)}
    99→
   100→        input.click(); //initiliaze click to open the file selector
   101→    };
   102→
   103→    const toolbarLink = [
