     2→import { DecoratorNode, COMMAND_PRIORITY_EDITOR, createCommand } from "lexical";
     3→import ImageComponent from "../ImageComponent";
     4→import ResizableImageComponent from "../ResizableImageComponent";
     5→
     6→export const INSERT_IMAGE_COMMAND = createCommand('INSERT_IMAGE_COMMAND');
     7→
     8→export default class ImageNode extends DecoratorNode {
     9→  static getType() {
    10→    return "image";
    11→  }
    12→
    13→  static clone(node) {
    14→    return new ImageNode(
    15→      node.__src, 
    16→      node.__width,
    17→      node.__height,
    18→      node.__key,
    19→    );
    20→  }
    21→
    22→  constructor(src, width = 400, height = 300, key) {
    23→    super(key);
    24→    this.__src = src;
    25→    this.__width = width;
    26→    this.__height = height;
    27→  }
    28→
    29→  createDOM() {
    30→    const div = document.createElement("div");
    31→    div.className = 'image-container'
    32→    return div;
    33→  }
    34→
    35→  updateDOM() {
    36→    return false;
    37→  }
    38→
    39→  exportJSON() {
    40→    return {
    41→      type: "image",
    42→      version: 1,
    43→      src: this.__src,
    44→      width: this.__width,
    45→      height: this.__height,
    46→    };
    47→  }
    48→
    49→  static importJSON(serializedNode) {
    50→    const { src, width, height, filePath } = serializedNode;
    51→    return $createImageNode(src, width, height); 
    52→  }
    53→
    54→  // update dimensions when user resizes
    55→  setWidthAndHeight(width, height) {
    56→    const writable = this.getWritable();
    57→    writable.__width = width;
    58→    writable.__height = height;
    59→  }
    60→
    61→  getWidth() {
    62→    return this.__width;
    63→  }
    64→
    65→  getHeight() {
    66→    return this.__height;
    67→  }
    68→
    69→  decorate(editor) {
    70→    const src = this.__src;
    71→    const nodeKey = this.getKey();
    72→    const width = this.__width;
    73→    const height = this.__height
    74→    const isEditable = editor.isEditable();
    75→    return <ResizableImageComponent src={src} nodeKey={nodeKey} width={width} height={height} isEditable={isEditable}/>;
    76→  }
    77→}
    78→
    79→//helper function to create ImageNode
    80→export function $createImageNode(src, width = 400, height = 300,) {
    81→  return new ImageNode(src, width, height,);
    82→}
    83→

