     1→import { useEffect } from 'react';
     2→import { useLexicalComposerContext } from '@lexical/react/LexicalComposerContext';
     3→import { $createParagraphNode, $getRoot, $getSelection, $isRangeSelection, COMMAND_PRIORITY_EDITOR } from 'lexical';
     4→import { $createImageNode, INSERT_IMAGE_COMMAND } from '../ImageNode';
     5→import { $createHeadingNode } from '@lexical/rich-text';
     6→
     7→export default function ImagePlugin({addUploadedImagePath}) {
     8→  const [editor] = useLexicalComposerContext();
     9→
    10→  useEffect(() => {
    11→    return editor.registerCommand(
    12→      INSERT_IMAGE_COMMAND,
    13→      (payload) => {
    14→        const { src, width, height} = payload;
    15→
    16→        const filePath = src.split('/journal-images/').pop(); // e.g., 'images/12345.jpg'
    17→
    18→        if(filePath){
    19→          addUploadedImagePath(filePath)
    20→        } else {
    21→          console.warn('Could not extract filePath from src:', src);
    22→        }
    23→        
    24→        const imageNode = $createImageNode(src, width, height, filePath);
    25→        const paragraphNode = $createParagraphNode();
    26→        const selection = $getSelection();
    27→        
    28→        if($isRangeSelection(selection)){
    29→           selection.insertNodes([imageNode]);
    30→        }else {
    31→          const root = $getRoot();
    32→          root.append(imageNode)
    33→          root.append(paragraphNode)
    34→        }
    35→        
    36→       
    37→
    38→        return true;
    39→      },
    40→      COMMAND_PRIORITY_EDITOR
    41→    );
    42→  }, [editor]);
    43→
    44→  return null;
    45→}

