     1→import { useLexicalComposerContext } from "@lexical/react/LexicalComposerContext";
     2→import { useEffect, useState } from "react";
     3→import ImageNode from "../ImageNode";
     4→import ImageComponent from "../../ImageComponent";
     5→
     6→const CustomImagePlugin = () => {
     7→  const [editor] = useLexicalComposerContext();
     8→  const [images, setImages] = useState([]);
     9→
    10→  useEffect(() => {
    11→    if (!editor.hasNodes([ImageNode])) {
    12→      throw new Error("CustomImagePlugin: ImageNode not registered on editor");
    13→    }
    14→
    15→    const updateImages = () => {
    16→      editor.getEditorState().read(() => {
    17→        const nodes = editor.getEditorState()._nodeMap;
    18→        const imageNodes = [];
    19→        nodes.forEach((node) => {
    20→          if (node.__type === "image") {
    21→            imageNodes.push({ key: node.__key, src: node.__src });
    22→          }
    23→        });
    24→        setImages(imageNodes);
    25→      });
    26→    };
    27→
    28→    updateImages();
    29→    return editor.registerUpdateListener(updateImages);
    30→  }, [editor]);
    31→
    32→  return (
    33→    <div>
    34→      {images.map(({ key, src }) => (
    35→        <ImageComponent key={key} src={src} nodeKey={key} />
    36→      ))}
    37→    </div>
    38→  );
    39→}
    40→export default CustomImagePlugin;

